class _QuickPresetChip extends StatelessWidget {
  final IconData icon;
  final String label;
  final bool isSelected;
  final VoidCallback onTap;

  const _QuickPresetChip({
    required this.icon,
    required this.label,
    required this.isSelected,
    required this.onTap,
  });

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Semantics(
      button: true,
      selected: isSelected,
      label: isSelected
          ? '$label export preset, selected'
          : '$label export preset',
      child: InkWell(
        onTap: onTap,
        borderRadius: BorderRadius.circular(12),
        child: ConstrainedBox(
          constraints: const BoxConstraints(minHeight: 48),
          child: Container(
            padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 12),
            decoration: BoxDecoration(
              color: isSelected
                  ? theme.colorScheme.primaryContainer
                  : theme.colorScheme.surfaceContainerHighest,
              borderRadius: BorderRadius.circular(12),
              border: isSelected
                  ? Border.all(color: theme.colorScheme.primary, width: 2)
                  : null,
            ),
            child: Row(
              mainAxisSize: MainAxisSize.min,
              children: [
                Icon(
                  icon,
                  size: 18,
                  color: isSelected
                      ? theme.colorScheme.primary
                      : theme.colorScheme.onSurface.withValues(alpha: 0.7),
                ),
                const SizedBox(width: 8),
                Text(
                  label,
                  style: theme.textTheme.bodyMedium?.copyWith(
                    color: isSelected
                        ? theme.colorScheme.primary
                        : theme.colorScheme.onSurface.withValues(alpha: 0.7),
                    fontWeight:
                        isSelected ? FontWeight.bold : FontWeight.normal,
                  ),
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }
}

class _SummaryRow extends StatelessWidget {
  final IconData icon;
  final String label;
  final String value;

  const _SummaryRow({
    required this.icon,
    required this.label,
    required this.value,
  });

  @override
  Widget build(BuildContext context) {
    final theme = Theme.of(context);

    return Row(
      children: [
        Icon(
          icon,
          size: 16,
          color: theme.colorScheme.onSurface.withValues(alpha: 0.5),
        ),
        const SizedBox(width: 8),
        Text(
          label,
          style: theme.textTheme.bodySmall?.copyWith(
            color: theme.colorScheme.onSurface.withValues(alpha: 0.7),
          ),
        ),
        const Spacer(),
        Text(
          value,
          style: theme.textTheme.bodySmall?.copyWith(
            fontWeight: FontWeight.bold,
          ),
        ),
      ],
    );
  }
}

import 'package:flutter_test/flutter_test.dart';
import 'package:flutter_fractals/core/models/export_options.dart';

void main() {
  group('ExportFormat', () {
    test('extension returns correct file extensions', () {
      expect(ExportFormat.png.extension, 'png');
      expect(ExportFormat.jpg.extension, 'jpg');
      expect(ExportFormat.webp.extension, 'webp');
    });

    test('mimeType returns correct MIME types', () {
      expect(ExportFormat.png.mimeType, 'image/png');
      expect(ExportFormat.jpg.mimeType, 'image/jpeg');
      expect(ExportFormat.webp.mimeType, 'image/webp');
    });
  });

  group('ExportResolution', () {
    test('dimensions returns correct values for preset resolutions', () {
      expect(ExportResolution.hd.dimensions, (1280, 720));
      expect(ExportResolution.fullHd.dimensions, (1920, 1080));
      expect(ExportResolution.quadHd.dimensions, (2560, 1440));
      expect(ExportResolution.uhd4k.dimensions, (3840, 2160));
      expect(ExportResolution.instagram.dimensions, (1080, 1080));
      expect(ExportResolution.instagramStory.dimensions, (1080, 1920));
      expect(ExportResolution.twitter.dimensions, (1200, 675));
    });

    test('screen and custom resolutions return null dimensions', () {
      expect(ExportResolution.screen.dimensions, isNull);
      expect(ExportResolution.custom.dimensions, isNull);
    });

    test('isSocialPreset identifies social presets correctly', () {
      expect(ExportResolution.instagram.isSocialPreset, isTrue);
      expect(ExportResolution.instagramStory.isSocialPreset, isTrue);
      expect(ExportResolution.twitter.isSocialPreset, isTrue);
      expect(ExportResolution.fullHd.isSocialPreset, isFalse);
      expect(ExportResolution.uhd4k.isSocialPreset, isFalse);
    });
  });

  group('ExportOptions', () {
    test('default options have sensible values', () {
      const options = ExportOptions();
      expect(options.format, ExportFormat.png);
      expect(options.resolution, ExportResolution.fullHd);
      expect(options.quality, 95);
      expect(options.embedMetadata, isTrue);
      expect(options.transparentBackground, isFalse);
    });

    test('calculatePixelRatio returns correct ratio for preset resolutions',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      // Portrait screen 400x800 -> Full HD adapts to 1080x1920.
      // Ratios: 1080/400 = 2.7, 1920/800 = 2.4 -> max = 2.7
      final ratio = options.calculatePixelRatio(400, 800);
      expect(ratio, closeTo(2.7, 0.1));
    });

    test('calculatePixelRatio is clamped to 8.0 max', () {
      const options = ExportOptions(resolution: ExportResolution.uhd4k);
      // Screen 100x100 -> would need 38.4 ratio, but clamped to 8
      final ratio = options.calculatePixelRatio(100, 100);
      expect(ratio, 8.0);
    });

    test('calculatePixelRatio sanitizes invalid screen dimensions for presets',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);

      expect(options.calculatePixelRatio(-400, -800), 8.0);
    });

    test('getTargetDimensions returns correct dimensions', () {
      const options = ExportOptions(resolution: ExportResolution.instagram);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1080));
    });

    test('getTargetDimensions adapts preset orientation to screen orientation',
        () {
      const options = ExportOptions(resolution: ExportResolution.fullHd);
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (1080, 1920));
    });

    test('social preset dimensions preserve platform crop contracts', () {
      const instagramStory = ExportOptions(
        resolution: ExportResolution.instagramStory,
      );
      const twitter = ExportOptions(resolution: ExportResolution.twitter);

      expect(instagramStory.getTargetDimensions(1200, 800), (1080, 1920));
      expect(twitter.getTargetDimensions(400, 800), (1200, 675));
      expect(
        instagramStory.calculatePixelRatio(1200, 800),
        closeTo(2.4, 0.01),
      );
    });

    test('custom resolution uses customWidth and customHeight', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );
      final dims = options.getTargetDimensions(400, 800);
      expect(dims, (2000, 1500));
    });

    test('custom resolution ignores non-positive dimensions', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 0,
        customHeight: -10,
      );

      expect(options.getTargetDimensions(400, 800), (400, 800));
      expect(options.calculatePixelRatio(400, 800), 1.0);
    });

    test('custom resolution can fall back one axis at a time', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 0,
      );

      expect(options.getTargetDimensions(400, 800), (2000, 800));
      expect(options.calculatePixelRatio(400, 800), 5.0);
    });

    test('custom resolution clamps huge dimensions to safe image bounds', () {
      const options = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 1 << 40,
        customHeight: 1 << 35,
      );

      expect(options.getTargetDimensions(400, 800), (1 << 30, 1 << 30));
      expect(options.calculatePixelRatio(400, 800), 8.0);
    });

    test('screen dimensions used for fallback are at least one pixel', () {
      const options = ExportOptions(resolution: ExportResolution.custom);

      expect(options.getTargetDimensions(0, -20), (1, 1));
      expect(options.calculatePixelRatio(0, -20), 1.0);
    });

    test('copyWith creates new instance with updated values', () {
      const original = ExportOptions();
      final updated = original.copyWith(
        format: ExportFormat.jpg,
        quality: 80,
      );

      expect(updated.format, ExportFormat.jpg);
      expect(updated.quality, 80);
      expect(updated.resolution, original.resolution); // Unchanged
    });

    test('copyWith clears nullable custom dimensions when null is explicit',
        () {
      const original = ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 2000,
        customHeight: 1500,
      );

      final updated = original.copyWith(
        customWidth: null,
        customHeight: null,
      );

      expect(updated.customWidth, isNull);
      expect(updated.customHeight, isNull);
      expect(updated.getTargetDimensions(400, 800), (400, 800));
    });

    test('copyWith clears nullable provenance fields when null is explicit',
        () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(
        metadata: null,
        watermarkText: null,
      );

      expect(updated.metadata, isNull);
      expect(updated.watermarkText, isNull);
    });

    test('copyWith omits nullable provenance fields without clearing them', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );
      final original = ExportOptions(
        metadata: metadata,
        watermarkText: 'Flutter Fractals',
      );

      final updated = original.copyWith(quality: 80);

      expect(updated.metadata, same(metadata));
      expect(updated.watermarkText, 'Flutter Fractals');
    });
  });

  group('ExportMetadata', () {
    test('toExifMap returns expected keys', () {
      final metadata = ExportMetadata(
        fractalType: 'mandelbrot',
        parameters: const {'iterations': 100},
        createdAt: DateTime(2024, 1, 15),
      );

      final exif = metadata.toExifMap();
      expect(exif, containsPair('Software', contains('Flutter Fractals')));
      expect(exif, containsPair('Artist', 'Flutter Fractals'));
      expect(exif, containsPair('UserComment', contains('mandelbrot')));
    });
  });

  group('ExportPresets', () {
    test('socialShare preset has correct settings', () {
      expect(ExportPresets.socialShare.format, ExportFormat.jpg);
      expect(ExportPresets.socialShare.resolution, ExportResolution.instagram);
      expect(ExportPresets.socialShare.quality, 90);
    });

    test('highQualityPng preset has correct settings', () {
      expect(ExportPresets.highQualityPng.format, ExportFormat.png);
      expect(ExportPresets.highQualityPng.resolution, ExportResolution.uhd4k);
    });

    test('webOptimized preset has correct settings', () {
      expect(ExportPresets.webOptimized.format, ExportFormat.webp);
      expect(ExportPresets.webOptimized.resolution, ExportResolution.fullHd);
      expect(ExportPresets.webOptimized.quality, 85);
    });

    test('transparentOverlay preset has correct settings', () {
      expect(ExportPresets.transparentOverlay.format, ExportFormat.png);
      expect(ExportPresets.transparentOverlay.transparentBackground, isTrue);
    });
  });
}

import 'package:flutter/material.dart';
import 'package:flutter_fractals/core/models/export_options.dart';
import 'package:flutter_fractals/features/export/export_options_sheet.dart';
import 'package:flutter_fractals/l10n/app_localizations.dart';
import 'package:flutter_test/flutter_test.dart';

class _SheetHarness {
  ExportSheetSubmission? submission;
}

void main() {
  Future<_SheetHarness> pumpSheet(
    WidgetTester tester, {
    ExportOptions initialOptions = const ExportOptions(),
  }) async {
    final harness = _SheetHarness();
    await tester.pumpWidget(
      MaterialApp(
        locale: const Locale('en'),
        localizationsDelegates: AppLocalizations.localizationsDelegates,
        supportedLocales: AppLocalizations.supportedLocales,
        home: Scaffold(
          body: Builder(
            builder: (context) => Center(
              child: ElevatedButton(
                onPressed: () async {
                  harness.submission = await ExportOptionsSheet.show(
                    context,
                    initialOptions: initialOptions,
                    fractalType: 'mandelbrot',
                  );
                },
                child: const Text('Open'),
              ),
            ),
          ),
        ),
      ),
    );
    await tester.tap(find.text('Open'));
    await tester.pumpAndSettle();
    return harness;
  }

  Future<ExportSheetSubmission?> pumpSheetAndSubmit(
    WidgetTester tester, {
    required Finder submitButton,
    ExportOptions initialOptions = const ExportOptions(),
  }) async {
    final harness = await pumpSheet(
      tester,
      initialOptions: initialOptions,
    );
    await tester.tap(submitButton);
    await tester.pumpAndSettle();
    return harness.submission;
  }

  testWidgets('save action triggers saveOnly export action', (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportSaveButton')),
    );

    expect(submission?.action, ExportAction.saveOnly);
  });

  testWidgets('share action triggers saveAndShare export action',
      (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportShareButton')),
    );

    expect(submission?.action, ExportAction.saveAndShare);
  });

  testWidgets('custom resolution export includes default dimensions',
      (tester) async {
    final submission = await pumpSheetAndSubmit(
      tester,
      submitButton: find.byKey(const ValueKey('exportSaveButton')),
      initialOptions: const ExportOptions(resolution: ExportResolution.custom),
    );

    expect(submission, isNotNull);
    expect(submission!.options.resolution, ExportResolution.custom);
    expect(submission.options.customWidth, 1920);
    expect(submission.options.customHeight, 1080);
  });

  testWidgets('custom fields remain export source after preset round-trip',
      (tester) async {
    tester.view.physicalSize = const Size(800, 1200);
    tester.view.devicePixelRatio = 1;
    addTearDown(tester.view.reset);

    final harness = await pumpSheet(
      tester,
      initialOptions: const ExportOptions(
        resolution: ExportResolution.custom,
        customWidth: 333,
        customHeight: 444,
      ),
    );

    await tester.tap(find.text('Customize').last);
    await tester.pumpAndSettle();

    await tester.tap(find.text('Web'));
    await tester.pumpAndSettle();

    await tester.tap(find.text(ExportResolution.custom.displayName));
    await tester.pumpAndSettle();

    expect(find.widgetWithText(TextField, '333'), findsOneWidget);
    expect(find.widgetWithText(TextField, '444'), findsOneWidget);

    await tester.tap(find.byKey(const ValueKey('exportSaveButton')));
    await tester.pumpAndSettle();

    expect(harness.submission, isNotNull);
    expect(harness.submission!.options.resolution, ExportResolution.custom);
    expect(harness.submission!.options.customWidth, 333);
    expect(harness.submission!.options.customHeight, 444);
  });

  testWidgets('sheet helper returns null when dismissed', (tester) async {
    ExportSheetSubmission? submission;

    await tester.pumpWidget(
      MaterialApp(
        locale: const Locale('en'),
        localizationsDelegates: AppLocalizations.localizationsDelegates,
        supportedLocales: AppLocalizations.supportedLocales,
        home: Scaffold(
          body: Builder(
            builder: (context) => Center(
              child: ElevatedButton(
                onPressed: () async {
                  submission = await ExportOptionsSheet.show(
                    context,
                    initialOptions: const ExportOptions(),
                    fractalType: 'mandelbrot',
                  );
                },
                child: const Text('Open'),
              ),
            ),
          ),
        ),
      ),
    );

    await tester.tap(find.text('Open'));
    await tester.pumpAndSettle();
    await tester.tapAt(const Offset(20, 20));
    await tester.pumpAndSettle();

    expect(submission, isNull);
  });
}

import 'dart:collection';
import 'dart:convert';
import 'dart:io';

import 'package:flutter/foundation.dart';
import 'package:path_provider/path_provider.dart';

/// Severity levels for log entries.
enum LogLevel { debug, info, warn, error }

/// JSON-safe structured data attached to an in-memory log entry.
///
/// Logger callers often pass diagnostic objects that are useful in debug text
/// but are not directly JSON encodable (for example [DateTime], enum values,
/// non-finite doubles, or opaque objects). Snapshot at the record boundary so
/// debug log lines and exported JSON remain replayable even if callers mutate
/// their original metadata map later.
class _LogStructuredData {
  const _LogStructuredData._();

  static Map<String, Object?>? snapshot(Map<String, Object?>? data) {
    if (data == null) return null;
    return Map<String, Object?>.unmodifiable({
      for (final entry in data.entries) entry.key: snapshotValue(entry.value),
    });
  }

  static Object? snapshotValue(Object? value) {
    if (value == null || value is String || value is bool) return value;
    if (value is num) return value.isFinite ? value : value.toString();
    if (value is DateTime) return value.toIso8601String();
    if (value is Enum) return value.name;
    if (value is List) {
      return List<Object?>.unmodifiable(value.map(snapshotValue));
    }
    if (value is Map) {
      return Map<String, Object?>.unmodifiable({
        for (final entry in value.entries)
          entry.key.toString(): snapshotValue(entry.value),
      });
    }
    return value.toString();
  }
}

/// A single timestamped log entry.
class LogEntry {
  LogEntry({
    required this.timestamp,
    required this.level,
    required this.category,
    required this.message,
    Map<String, Object?>? data,
  }) : data = _LogStructuredData.snapshot(data);

  final DateTime timestamp;
  final LogLevel level;

  /// Short tag: 'action', 'render', 'gpu', 'state', 'lifecycle', 'export', etc.
  final String category;
  final String message;

  /// Optional structured data (e.g. fractal state snapshot).
  final Map<String, Object?>? data;

  Map<String, Object?> toJson() => {
        't': timestamp.toIso8601String(),
        'level': level.name,
        'cat': category,
        'msg': message,
        if (data != null) 'data': data,
      };

  /// Serialises to a JSONL line using the on-disk schema.
  Map<String, Object?> toDiskJson() => {
        'timestamp': timestamp.toIso8601String(),
        'level': level.name,
        'tag': category,
        'message': message,
      };

  /// Deserialises from the on-disk JSONL schema.
  factory LogEntry.fromDiskJson(Map<String, dynamic> json) {
    return LogEntry(
      timestamp: DateTime.parse(json['timestamp'] as String),
      level: LogLevel.values.firstWhere(
        (l) => l.name == (json['level'] as String),
        orElse: () => LogLevel.info,
      ),
      category: json['tag'] as String? ?? '',
      message: json['message'] as String? ?? '',
    );
  }

  String toLogLine() {
    final ts =
        '${timestamp.hour.toString().padLeft(2, '0')}:${timestamp.minute.toString().padLeft(2, '0')}:${timestamp.second.toString().padLeft(2, '0')}.${timestamp.millisecond.toString().padLeft(3, '0')}';
    final dataStr = data != null ? ' ${jsonEncode(data)}' : '';
    return '[$ts][${level.name}][$category] $message$dataStr';
  }
}

/// Replayable result of rotating an on-disk JSONL log file.
@immutable
class LogDiskRotationPlan {
  const LogDiskRotationPlan({
    required this.keptLines,
    required this.nonEmptyLineCount,
  });

  /// Non-empty JSONL lines kept in chronological order.
  final List<String> keptLines;

  /// Count of non-empty candidate lines before rotation.
  final int nonEmptyLineCount;

  bool get shouldRewrite => keptLines.length < nonEmptyLineCount;

  int get keptUtf8Bytes => keptLines.fold<int>(
        0,
        (total, line) => total + utf8.encode(line).length + 1,
      );

  String serializeKeptLines() => keptLines.map((line) => '$line\n').join();
}

/// Pure on-disk log rotation policy.
///
/// Keeps the most recent non-empty lines as one chronological suffix constrained
/// by entry count and byte budget. Exposing the selection makes dropped-line and
/// byte-budget assumptions testable without touching platform cache files.
class LogDiskRotationPolicy {
  const LogDiskRotationPolicy._();

  static LogDiskRotationPlan plan({
    required List<String> lines,
    required int maxEntries,
    required int maxBytes,
  }) {
    assert(maxEntries > 0, 'maxEntries must be positive');
    assert(maxBytes > 0, 'maxBytes must be positive');

    final nonEmptyLineCount =
        lines.where((line) => line.trim().isNotEmpty).length;
    final keptReversed = <String>[];
    var totalBytes = 0;

    for (final line in lines.reversed) {
      if (line.trim().isEmpty) continue;
      if (keptReversed.length >= maxEntries) break;
      final lineBytes = utf8.encode(line).length + 1; // +1 for newline
      if (totalBytes + lineBytes > maxBytes) break;
      totalBytes += lineBytes;
      keptReversed.add(line);
    }

    return LogDiskRotationPlan(
      keptLines: keptReversed.reversed.toList(growable: false),
      nonEmptyLineCount: nonEmptyLineCount,
    );
  }
}

/// Global in-memory ring-buffer logger with optional persistent JSONL storage.
///
/// Keeps the last [maxEntries] log entries in memory. Export as text or JSON
/// at any time via [exportText] / [exportJson].
///
/// Call [init] once at app startup to enable persistence:
/// ```dart
/// await AppLogger.instance.init();
/// ```
///
/// Usage:
/// ```dart
/// AppLogger.instance.log('action', 'User tapped zoom reset');
/// AppLogger.instance.logState('render', 'Backend switched', {'backend': 'cpu', 'reason': 'gpu_health'});
/// ```
class AppLogger extends ChangeNotifier {
  AppLogger._({this.maxEntries = 2000}); // ignore: unused_element_parameter

  static final AppLogger instance = AppLogger._();

  /// Maximum entries kept in the ring buffer.
  final int maxEntries;

  /// Maximum entries persisted to disk (rotation threshold).
  static const int _maxDiskEntries = 5000;

  /// Approximate size cap for the on-disk file (~2 MB).
  static const int _maxDiskBytes = 2 * 1024 * 1024;

  final Queue<LogEntry> _entries = Queue<LogEntry>();

  File? _logFile;
  IOSink? _sink;
  bool _persistenceReady = false;

  /// Read-only view of all entries (oldest first).
  List<LogEntry> get entries => _entries.toList(growable: false);

  int get length => _entries.length;

  // ── Initialisation ──────────────────────────────────────────────────

  /// Initialise persistent storage. Safe to call multiple times; subsequent
  /// calls are no-ops. Skipped automatically on web (no filesystem).
  Future<void> init() async {
    if (_persistenceReady) return;
    if (kIsWeb) return;

    try {
      final cacheDir = await getApplicationCacheDirectory();
      _logFile = File('${cacheDir.path}/fractal_forge_logs.jsonl');
      await _loadFromDisk();
      _sink = _logFile!.openWrite(mode: FileMode.append);
      _persistenceReady = true;
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to init persistence: $e');
      }
      // Graceful degradation: continue with in-memory only.
      _logFile = null;
      _sink = null;
    }
  }

  // ── Disk I/O ────────────────────────────────────────────────────────

  Future<void> _loadFromDisk() async {
    final file = _logFile;
    if (file == null || !file.existsSync()) return;

    try {
      final lines = await file.readAsLines();

      // Rotation: keep only the last _maxDiskEntries lines that fit within
      // _maxDiskBytes when re-encoded.
      final rotation = LogDiskRotationPolicy.plan(
        lines: lines,
        maxEntries: _maxDiskEntries,
        maxBytes: _maxDiskBytes,
      );

      // If we trimmed anything, rewrite the file to reclaim space.
      if (rotation.shouldRewrite) {
        await file.writeAsString(rotation.serializeKeptLines());
      }

      // Parse and load into ring buffer (in-memory max still applies).
      for (final line in rotation.keptLines) {
        try {
          final json = jsonDecode(line) as Map<String, dynamic>;
          final entry = LogEntry.fromDiskJson(json);
          _entries.addLast(entry);
          while (_entries.length > maxEntries) {
            _entries.removeFirst();
          }
        } catch (_) {
          // Skip malformed lines.
        }
      }
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to load log from disk: $e');
      }
    }
  }

  void _appendToDisk(LogEntry entry) {
    final sink = _sink;
    if (sink == null) return;

    try {
      sink.writeln(jsonEncode(entry.toDiskJson()));
    } catch (e) {
      if (kDebugMode) {
        debugPrint('[AppLogger] Failed to write log entry to disk: $e');
      }
    }
  }

  // ── Logging methods ────────────────────────────────────────────────

  void log(String category, String message,
      {LogLevel level = LogLevel.info, Map<String, Object?>? data}) {
    final entry = LogEntry(
      timestamp: DateTime.now(),
      level: level,
      category: category,
      message: message,
      data: data,
    );
    _entries.addLast(entry);
    while (_entries.length > maxEntries) {
      _entries.removeFirst();
    }
    if (kDebugMode) {
      debugPrint(entry.toLogLine());
    }
    _appendToDisk(entry);
    notifyListeners();
  }

  /// Convenience: log with structured data.
  void logState(String category, String message, Map<String, Object?> data,
      {LogLevel level = LogLevel.info}) {
    log(category, message, level: level, data: data);
  }

  void debug(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.debug, data: data);

  void info(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.info, data: data);

  void warn(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.warn, data: data);

  void error(String category, String message, {Map<String, Object?>? data}) =>
      log(category, message, level: LogLevel.error, data: data);

